example.code:
# order/domain/repositories.py -- domain layer, no ORM imports from abc import ABC, abstractmethod from typing import List, Optional from uuid import UUID
from .entities.order import Order
class OrderRepository(ABC): """Repository interface for Order aggregate."""
@abstractmethod async def find_by_id(self, order_id: UUID) -> Optional[Order]: """Find order by ID.""" pass
@abstractmethod async def find_by_customer(self, customer_id: UUID) -> List[Order]: """Find all orders for a customer.""" pass
@abstractmethod async def save(self, order: Order) -> None: """Save order (insert or update).""" pass
@abstractmethod async def delete(self, order: Order) -> None: """Delete order.""" pass
# order/infrastructure/repositories.py -- infrastructure layer class SQLAlchemyOrderRepository(OrderRepository): """SQLAlchemy implementation of OrderRepository."""
def __init__(self, session): self._session = session
async def find_by_id(self, order_id: UUID) -> Optional[Order]: model = await self._session.get(OrderModel, order_id) return self._to_entity(model) if model else None
async def save(self, order: Order) -> None: model = self._to_model(order) self._session.add(model) # Events will be dispatched after commit
def _to_entity(self, model: OrderModel) -> Order: return Order( id=model.id, customer_id=model.customer_id, status=OrderStatus(model.status), lines=[ OrderLine( product_id=line.product_id, product_name=line.product_name, quantity=line.quantity, unit_price=Money(line.unit_price, line.currency), ) for line in model.lines ], shipping_address=Address( street=model.shipping_street, city=model.shipping_city, state=model.shipping_state, postal_code=model.shipping_postal, country=model.shipping_country, ) if model.shipping_street else None, placed_at=model.placed_at, )

# BAD: domain imports SQLAlchemy Session directly
from sqlalchemy.orm import Session

class OrderRepository:
    def __init__(self, session: Session):  # ORM type in domain!
        self.session = session

    def find_by_id(self, order_id):
        # Returns ORM model, not domain Aggregate
        return self.session.query(OrderModel).filter_by(id=order_id).first()
